Application::Application()
    : event_group_(nullptr)
    , clock_timer_handle_(nullptr)
    , aec_mode_(kAecOff)
    , clock_ticks_(0)
    , activation_task_handle_(nullptr)
    , assets_version_checked_(false)
    , has_server_time_(false)
    , play_popup_on_listening_(false)
    , aborted_(false)
    , listening_mode_(kListeningModeAutoStop)
{
    // Create event group for inter-task communication
    event_group_ = xEventGroupCreate();
    if (event_group_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
    }

    // Create the clock timer to generate periodic clock tick events
    esp_timer_create_args_t timer_args = {};
    timer_args.callback = [](void* arg) {
        Application* app = static_cast<Application*>(arg);
        if (app->event_group_ != nullptr) {
            xEventGroupSetBits(app->event_group_, MAIN_EVENT_CLOCK_TICK);
        }
    };
    timer_args.arg = this;
    timer_args.name = "clock_timer";

    esp_err_t err = esp_timer_create(&timer_args, &clock_timer_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create clock timer: %s", esp_err_to_name(err));
    }

    // Initialize AEC mode based on configuration settings
    // Default to AEC off, but this could be loaded from persistent storage
    Settings settings("system");
    int saved_aec_mode = settings.GetInt("aec_mode", kAecOff);

    // Ensure mutual exclusivity and valid range
    if (saved_aec_mode >= kAecOff && saved_aec_mode <= kAecOnDeviceSide) {
        aec_mode_ = static_cast<AecMode>(saved_aec_mode);
    } else {
        aec_mode_ = kAecOff;
        ESP_LOGW(TAG, "Invalid AEC mode loaded, defaulting to kAecOff");
    }
}

