void Application::CheckNewVersion()
{
    const int MAX_RETRY = 10;
    int retry_count = 0;
    int retry_delay = 10; // Initial retry delay in seconds

    auto &board = Board::GetInstance();
    while (true)
    {
        auto display = board.GetDisplay();
        display->SetStatus(Lang::Strings::CHECKING_NEW_VERSION);

        esp_err_t err = ota_->CheckVersion();
        if (err != ESP_OK)
        {
            retry_count++;
            if (retry_count >= MAX_RETRY)
            {
                ESP_LOGE(TAG, "Too many retries, exit version check");
                return;
            }

            char error_message[128];
            snprintf(error_message, sizeof(error_message), "code=%d, url=%s", err, ota_->GetCheckVersionUrl().c_str());
            char buffer[256];
            snprintf(buffer, sizeof(buffer), Lang::Strings::CHECK_NEW_VERSION_FAILED, retry_delay, error_message);
            Alert(Lang::Strings::ERROR, buffer, "cloud_slash", Lang::Sounds::OGG_EXCLAMATION);

            ESP_LOGW(TAG, "Check new version failed, retry in %d seconds (%d/%d)", retry_delay, retry_count, MAX_RETRY);
            for (int i = 0; i < retry_delay; i++)
            {
                vTaskDelay(pdMS_TO_TICKS(1000));
                if (GetDeviceState() == kDeviceStateIdle)
                {
                    break;
                }
            }
            retry_delay *= 2; // Double the retry delay
            continue;
        }
        retry_count = 0;
        retry_delay = 10; // Reset retry delay

        // Check if there's an activation challenge that needs to be handled
        if (ota_->HasActivationChallenge())
        {
            // Handle activation challenge
            ESP_LOGI(TAG, "Activation challenge received");
            // The actual activation will be handled in the Activate() call later
        }

        // Check if there's an activation code to display
        if (ota_->HasActivationCode())
        {
            ShowActivationCode(ota_->GetActivationCode(), ota_->GetActivationMessage());
        }

        // Check if there's a new firmware version
        if (ota_->HasNewVersion())
        {
            // Perform firmware upgrade
            if (!UpgradeFirmware(ota_->GetFirmwareUrl(), ota_->GetFirmwareVersion()))
            {
                ESP_LOGE(TAG, "Firmware upgrade failed");
                // Continue with activation even if upgrade fails
            }
            else
            {
                // Upgrade successful, device will reboot
                return;
            }
        }
        else
        {
            // No new version available, mark current firmware as valid
            ota_->MarkCurrentVersionValid();
            ESP_LOGI(TAG, "Current firmware version is valid");
        }

        // Exit the loop after successful version check
        break;
    }
}

