    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        partition_valid_ = false;
        return false;
    }

    // Check if partition has sufficient space (at least some minimum size)
    if (partition_->size < sizeof(mmap_assets_table)) {
        ESP_LOGE(TAG, "Assets partition too small: %lu bytes", partition_->size);
        partition_valid_ = false;
        return false;
    }

    // Map the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, 
                                       reinterpret_cast<const void**>(&mmap_root_), &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        partition_valid_ = false;
        return false;
    }

    // Validate partition format and checksum
    if (mmap_root_ == nullptr) {
        ESP_LOGE(TAG, "Failed to map assets partition - null pointer");
        partition_valid_ = false;
        return false;
    }

    // Check magic number (assuming first 4 bytes are magic)
    const uint32_t* magic = reinterpret_cast<const uint32_t*>(mmap_root_);
    if (*magic != 0x41455341) { // "ASEA" in little-endian
        ESP_LOGE(TAG, "Invalid assets partition magic: 0x%08X", *magic);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        partition_valid_ = false;
        return false;
    }

    // Get partition header info (assuming structure: magic(4) + checksum(4) + asset_count(4) + reserved(4))
    const uint32_t* header = reinterpret_cast<const uint32_t*>(mmap_root_);
    uint32_t stored_checksum = *(header + 1);  // Second 4-byte word
    uint32_t asset_count = *(header + 2);      // Third 4-byte word

    // Calculate checksum of the partition data (excluding the checksum field itself)
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_ + 8, partition_->size - 8);

    if (stored_checksum != calculated_checksum) {
        ESP_LOGE(TAG, "Checksum mismatch: stored=0x%04X, calculated=0x%04X", 
                 stored_checksum, calculated_checksum);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        checksum_valid_ = false;
        partition_valid_ = false;
        return false;
    }

    checksum_valid_ = true;

    // Build asset index
    assets_.clear();

    // Assuming asset table starts after header (16 bytes)
    const mmap_assets_table* asset_table = reinterpret_cast<const mmap_assets_table*>(mmap_root_ + 16);

    for (uint32_t i = 0; i < asset_count && i < (partition_->size - 16) / sizeof(mmap_assets_table); i++) {
        const mmap_assets_table& entry = asset_table[i];

        // Skip empty entries
        if (entry.asset_name[0] == '\0' || entry.asset_size == 0) {
            continue;
        }

        // Validate asset offset and size
        if (entry.asset_offset + entry.asset_size > partition_->size) {
            ESP_LOGW(TAG, "Asset %s extends beyond partition bounds", entry.asset_name);
            continue;
        }

        // Add asset to index
        Asset asset;
        asset.size = entry.asset_size;
        asset.offset = entry.asset_offset;

        std::string asset_name(entry.asset_name);
        assets_[asset_name] = asset;

        ESP_LOGD(TAG, "Indexed asset: %s, size=%u, offset=%u", 
                 entry.asset_name, entry.asset_size, entry.asset_offset);
    }

    ESP_LOGI(TAG, "Successfully initialized assets partition with %d assets", assets_.size());
    partition_valid_ = true;
    return true;
}

