bool DeviceStateMachine::TransitionTo(DeviceState new_state) {
    DeviceState old_state = current_state_.load();

    // Check if the transition is valid
    if (!IsValidTransition(old_state, new_state)) {
        ESP_LOGW(TAG, "Invalid state transition requested: %s -> %s", 
                 GetStateName(old_state), GetStateName(new_state));
        return false;
    }

    // If transitioning to the same state, treat as no-op
    if (old_state == new_state) {
        ESP_LOGD(TAG, "No-op transition to same state: %s", GetStateName(new_state));
        return true;
    }

    // Perform the state transition atomically
    current_state_.store(new_state);

    // Log the successful transition
    ESP_LOGI(TAG, "State transition: %s -> %s", 
             GetStateName(old_state), GetStateName(new_state));

    // Notify all registered listeners about the state change
    NotifyStateChange(old_state, new_state);

    return true;
}

