void McpServer::DoToolCall(int id, const std::string &tool_name, const cJSON *tool_arguments)
{
    // Find the tool by name
    auto tool_iter = std::find_if(tools_.begin(), tools_.end(), 
                                 [&tool_name](const McpTool* tool) { 
                                     return tool->name() == tool_name; 
                                 });

    if (tool_iter == tools_.end()) {
        ESP_LOGE(TAG, "tools/call: Unknown tool: %s", tool_name.c_str());
        ReplyError(id, "Unknown tool: " + tool_name);
        return;
    }

    // Create a copy of the tool's property list to populate with arguments
    PropertyList arguments = (*tool_iter)->properties();

    try {
        // Process each expected property
        for (auto& argument : arguments) {
            bool found = false;

            // If tool_arguments is a valid object, look for this argument
            if (cJSON_IsObject(tool_arguments)) {
                auto value = cJSON_GetObjectItem(tool_arguments, argument.name().c_str());

                if (value != nullptr) {
                    // Type check and extract value based on expected type
                    if (argument.type() == kPropertyTypeBoolean && cJSON_IsBool(value)) {
                        argument.set_value<bool>(cJSON_IsTrue(value));
                        found = true;
                    } else if (argument.type() == kPropertyTypeInteger && cJSON_IsNumber(value)) {
                        argument.set_value<int>(value->valueint);
                        found = true;
                    } else if (argument.type() == kPropertyTypeString && cJSON_IsString(value)) {
                        argument.set_value<std::string>(std::string(value->valuestring));
                        found = true;
                    } else if (value != nullptr) {
                        // Value exists but type doesn't match
                        ESP_LOGE(TAG, "tools/call: Invalid type for argument: %s", argument.name().c_str());
                        ReplyError(id, "Invalid type for argument: " + argument.name());
                        return;
                    }
                }
            }

            // If argument is required but not found, return error
            if (!argument.has_default_value() && !found) {
                ESP_LOGE(TAG, "tools/call: Missing required argument: %s", argument.name().c_str());
                ReplyError(id, "Missing required argument: " + argument.name());
                return;
            }

            // If argument has default value and wasn't provided, use the default
            if (argument.has_default_value() && !found) {
                // The default value is already set in the Property constructor
                continue;
            }
        }
    } catch (const std::exception& e) {
        ESP_LOGE(TAG, "tools/call: %s", e.what());
        ReplyError(id, std::string("Argument parsing error: ") + e.what());
        return;
    }

    // Schedule the tool execution on the main application thread
    auto& app = Application::GetInstance();
    app.Schedule([this, id, tool_iter, arguments = std::move(arguments)]() mutable {
        try {
            std::string result = (*tool_iter)->Call(arguments);
            ReplyResult(id, result);
        } catch (const std::exception& e) {
            ESP_LOGE(TAG, "tools/call: Tool execution failed: %s", e.what());
            ReplyError(id, std::string("Tool execution failed: ") + e.what());
        } catch (...) {
            ESP_LOGE(TAG, "tools/call: Tool execution failed with unknown error");
            ReplyError(id, "Tool execution failed with unknown error");
        }
    });
}

