esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.empty()) {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_FAIL;
    }

    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP client");
        return ESP_FAIL;
    }

    // Get current firmware version
    const esp_app_desc_t* app_desc = esp_app_get_description();
    current_version_ = std::string(app_desc->version);

    ESP_LOGI(TAG, "Checking version, current version: %s", current_version_.c_str());

    if (!http->Open("GET", url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", url.c_str());
        return ESP_FAIL;
    }

    int status_code = http->GetStatusCode();
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP request failed with status code: %d", status_code);
        return status_code;
    }

    std::string response = http->ReadAll();
    if (response.empty()) {
        ESP_LOGE(TAG, "Empty response from server");
        return ESP_FAIL;
    }

    // Parse JSON response
    cJSON* json = cJSON_Parse(response.c_str());
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Reset flags
    has_new_version_ = false;
    has_mqtt_config_ = false;
    has_websocket_config_ = false;
    has_activation_code_ = false;
    has_server_time_ = false;
    has_activation_challenge_ = false;

    // Check for firmware update
    cJSON* firmware_obj = cJSON_GetObjectItem(json, "firmware");
    if (firmware_obj && cJSON_IsObject(firmware_obj)) {
        cJSON* version_item = cJSON_GetObjectItem(firmware_obj, "version");
        cJSON* url_item = cJSON_GetObjectItem(firmware_obj, "url");

        if (version_item && cJSON_IsString(version_item) && 
            url_item && cJSON_IsString(url_item)) {

            firmware_version_ = std::string(cJSON_GetStringValue(version_item));
            firmware_url_ = std::string(cJSON_GetStringValue(url_item));

            if (IsNewVersionAvailable(current_version_, firmware_version_)) {
                has_new_version_ = true;
                ESP_LOGI(TAG, "New firmware version available: %s", firmware_version_.c_str());
            } else {
                ESP_LOGI(TAG, "No new firmware version available");
            }
        }
    }

    // Check for activation challenge
    cJSON* activation_obj = cJSON_GetObjectItem(json, "activation");
    if (activation_obj && cJSON_IsObject(activation_obj)) {
        cJSON* challenge_item = cJSON_GetObjectItem(activation_obj, "challenge");
        if (challenge_item && cJSON_IsString(challenge_item)) {
            activation_challenge_ = std::string(cJSON_GetStringValue(challenge_item));
            has_activation_challenge_ = true;
            ESP_LOGI(TAG, "Activation challenge received");
        }

        cJSON* message_item = cJSON_GetObjectItem(activation_obj, "message");
        if (message_item && cJSON_IsString(message_item)) {
            activation_message_ = std::string(cJSON_GetStringValue(message_item));
        }

        cJSON* code_item = cJSON_GetObjectItem(activation_obj, "code");
        if (code_item && cJSON_IsString(code_item)) {
            activation_code_ = std::string(cJSON_GetStringValue(code_item));
            has_activation_code_ = true;
            ESP_LOGI(TAG, "Activation code received");
        }
    }

    // Check for MQTT config
    cJSON* mqtt_obj = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_obj && cJSON_IsObject(mqtt_obj)) {
        has_mqtt_config_ = true;
        ESP_LOGI(TAG, "MQTT configuration available");

        // Save MQTT config to settings
        Settings settings("mqtt", false);
        cJSON* host_item = cJSON_GetObjectItem(mqtt_obj, "host");
        cJSON* port_item = cJSON_GetObjectItem(mqtt_obj, "port");
        cJSON* username_item = cJSON_GetObjectItem(mqtt_obj, "username");
        cJSON* password_item = cJSON_GetObjectItem(mqtt_obj, "password");
        cJSON* client_id_item = cJSON_GetObjectItem(mqtt_obj, "client_id");

        if (host_item && cJSON_IsString(host_item)) {
            settings.SetString("host", cJSON_GetStringValue(host_item));
        }
        if (port_item && cJSON_IsNumber(port_item)) {
            settings.SetInt("port", port_item->valueint);
        }
        if (username_item && cJSON_IsString(username_item)) {
            settings.SetString("username", cJSON_GetStringValue(username_item));
        }
        if (password_item && cJSON_IsString(password_item)) {
            settings.SetString("password", cJSON_GetStringValue(password_item));
        }
        if (client_id_item && cJSON_IsString(client_id_item)) {
            settings.SetString("client_id", cJSON_GetStringValue(client_id_item));
        }
        settings.Save();
    }

    // Check for WebSocket config
    cJSON* websocket_obj = cJSON_GetObjectItem(json, "websocket");
    if (websocket_obj && cJSON_IsObject(websocket_obj)) {
        has_websocket_config_ = true;
        ESP_LOGI(TAG, "WebSocket configuration available");

        // Save WebSocket config to settings
        Settings settings("websocket", false);
        cJSON* url_item = cJSON_GetObjectItem(websocket_obj, "url");
        if (url_item && cJSON_IsString(url_item)) {
            settings.SetString("url", cJSON_GetStringValue(url_item));
            settings.Save();
        }
    }

    // Check for server time
    cJSON* server_time_item = cJSON_GetObjectItem(json, "server_time");
    if (server_time_item && cJSON_IsNumber(server_time_item)) {
        has_server_time_ = true;
        ESP_LOGI(TAG, "Server time received: %lld", server_time_item->valuedouble);

        // Save server time to settings
        Settings settings("system", false);
        settings.SetLongLong("server_time", (long long)server_time_item->valuedouble);
        settings.Save();
    }

    cJSON_Delete(json);

    ESP_LOGI(TAG, "Version check completed successfully");
    return ESP_OK;
}

