std::string Ota::GetActivationPayload()
{
    cJSON *root = cJSON_CreateObject();

    // If no serial number is available, return empty JSON object
    if (!has_serial_number_) {
        char *json_string = cJSON_PrintUnformatted(root);
        std::string result(json_string);
        cJSON_free(json_string);
        cJSON_Delete(root);
        return result;
    }

    // Add serial number to payload
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge to payload
    if (has_activation_challenge_) {
        cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());
    }

    // Compute HMAC-SHA256 signature
#ifdef SOC_HMAC_SUPPORTED
    if (has_activation_challenge_) {
        uint8_t hmac[32] = {0};
        esp_err_t err = esp_hmac_calculate(HMAC_KEY0, activation_challenge_.c_str(), activation_challenge_.length(), hmac);
        if (err == ESP_OK) {
            // Convert HMAC bytes to hex string
            char hmac_hex[65] = {0}; // 32 bytes * 2 chars per byte + null terminator
            for (int i = 0; i < 32; i++) {
                sprintf(&hmac_hex[i * 2], "%02x", hmac[i]);
            }
            cJSON_AddStringToObject(root, "signature", hmac_hex);
        } else {
            ESP_LOGE(TAG, "Failed to calculate HMAC: %s", esp_err_to_name(err));
        }
    }
#endif

    // Convert to JSON string
    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string);
    cJSON_free(json_string);
    cJSON_Delete(root);

    return result;
}

