esp_err_t Ota::Activate()
{
    // Check if we have an activation challenge to respond to
    if (!has_activation_challenge_)
    {
        ESP_LOGI(TAG, "No activation challenge, skipping activation");
        return ESP_OK;
    }

    // Construct activation URL by appending "/activate" to the base OTA URL
    std::string base_url = GetCheckVersionUrl();
    if (base_url.empty())
    {
        ESP_LOGE(TAG, "OTA URL is not properly set");
        return ESP_ERR_INVALID_ARG;
    }

    // Remove trailing slash if present
    if (base_url.back() == '/')
    {
        base_url.pop_back();
    }

    std::string activate_url = base_url + "/activate";
    ESP_LOGI(TAG, "Activating firmware at URL: %s", activate_url.c_str());

    // Setup HTTP connection with required headers
    auto http = SetupHttp();

    // Get the activation payload
    std::string payload = GetActivationPayload();
    http->SetContent(std::move(payload));

    // Open HTTP connection and send POST request
    if (!http->Open("POST", activate_url))
    {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation, code=0x%x", last_error);
        return last_error;
    }

    // Check HTTP status code
    auto status_code = http->GetStatusCode();
    if (status_code != 200 && status_code != 204)
    {
        ESP_LOGE(TAG, "Activation failed, status code: %d", status_code);
        http->Close();
        return status_code;
    }

    // Read response data if needed (though we may not need to process it)
    std::string response = http->ReadAll();
    http->Close();

    ESP_LOGI(TAG, "Activation successful, response: %s", response.c_str());
    return ESP_OK;
}

