void AudioService::AudioInputTask()
{
    const int kFrameDurationMs = OPUS_FRAME_DURATION_MS;
    const int kSampleRate = 16000;
    const int kFrameSize = kSampleRate * kFrameDurationMs / 1000;

    // Warmup frames to avoid initial noise
    const int kWarmupFrames = 3;
    int warmup_count = 0;

    while (!service_stopped_)
    {
        // Check which processing path is active
        EventBits_t event_bits = xEventGroupGetBits(event_group_);

        // If no processing is running, wait for a bit and continue
        if (!(event_bits & (AS_EVENT_AUDIO_TESTING_RUNNING | 
                           AS_EVENT_WAKE_WORD_RUNNING | 
                           AS_EVENT_AUDIO_PROCESSOR_RUNNING)))
        {
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Read audio data
        std::vector<int16_t> audio_frame;
        if (!ReadAudioData(audio_frame, kSampleRate, kFrameSize))
        {
            vTaskDelay(pdMS_TO_TICKS(5));
            continue;
        }

        // Handle warmup period for audio processor
        if (audio_input_need_warmup_ && (event_bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING))
        {
            warmup_count++;
            if (warmup_count >= kWarmupFrames)
            {
                audio_input_need_warmup_ = false;
                warmup_count = 0;
            }
            else
            {
                continue;
            }
        }

        // Route audio based on active processing paths
        if (event_bits & AS_EVENT_AUDIO_TESTING_RUNNING)
        {
            // Audio testing mode - encode to testing queue
            PushTaskToEncodeQueue(kAudioTaskTypeEncodeToTestingQueue, std::move(audio_frame));

            // Check if testing queue is getting full
            {
                std::lock_guard<std::mutex> lock(audio_queue_mutex_);
                if (audio_testing_queue_.size() >= MAX_DECODE_PACKETS_IN_QUEUE && 
                    callbacks_.on_audio_testing_queue_full)
                {
                    callbacks_.on_audio_testing_queue_full();
                }
            }
        }
        else if (event_bits & AS_EVENT_WAKE_WORD_RUNNING)
        {
            // Wake word detection mode
            if (wake_word_ && !audio_frame.empty())
            {
                wake_word_->FeedAudioData(audio_frame);
            }
        }
        else if (event_bits & AS_EVENT_AUDIO_PROCESSOR_RUNNING)
        {
            // General audio processing mode
            if (audio_processor_ && !audio_input_need_warmup_ && !audio_frame.empty())
            {
                audio_processor_->ProcessAudioFrame(std::move(audio_frame));
            }
        }
    }

    ESP_LOGW(TAG, "Audio input task stopped");
}

