void AudioService::OpusCodecTask()
{
    while (true)
    {
        std::unique_lock<std::mutex> lock(audio_queue_mutex_);

        // Wait for either encode or decode work to be available
        audio_queue_cv_.wait(lock, [this]()
                             { return !audio_encode_queue_.empty() || !audio_decode_queue_.empty() || service_stopped_; });

        if (service_stopped_)
        {
            break;
        }

        // Process encoding tasks (PCM -> Opus)
        if (!audio_encode_queue_.empty())
        {
            auto task = std::move(audio_encode_queue_.front());
            audio_encode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            switch (task->type)
            {
                case kAudioTaskTypeEncodeToSendQueue:
                {
                    // Encode PCM data to Opus for sending
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->sample_rate = 16000;
                    packet->frame_duration = OPUS_FRAME_DURATION_MS;
                    packet->timestamp = task->timestamp;

                    if (opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), packet->payload))
                    {
                        std::lock_guard<std::mutex> send_lock(audio_queue_mutex_);
                        if (audio_send_queue_.size() < MAX_SEND_PACKETS_IN_QUEUE)
                        {
                            audio_send_queue_.push_back(std::move(packet));
                            audio_queue_cv_.notify_all();

                            // Notify that send queue has data available
                            if (callbacks_.on_send_queue_available)
                            {
                                callbacks_.on_send_queue_available();
                            }
                        }
                        else
                        {
                            ESP_LOGW(TAG, "Send queue is full, dropping packet");
                        }
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Failed to encode audio data");
                    }
                    debug_statistics_.encode_count++;
                    break;
                }

                case kAudioTaskTypeEncodeToTestingQueue:
                {
                    // Encode PCM data for audio testing
                    auto packet = std::make_unique<AudioStreamPacket>();
                    packet->sample_rate = 16000;
                    packet->frame_duration = OPUS_FRAME_DURATION_MS;

                    if (opus_encoder_->Encode(task->pcm.data(), task->pcm.size(), packet->payload))
                    {
                        std::lock_guard<std::mutex> test_lock(audio_queue_mutex_);
                        if (audio_testing_queue_.size() < AUDIO_TESTING_MAX_DURATION_MS / OPUS_FRAME_DURATION_MS)
                        {
                            audio_testing_queue_.push_back(std::move(packet));
                        }
                        else
                        {
                            ESP_LOGW(TAG, "Audio testing queue is full");
                            if (callbacks_.on_audio_testing_queue_full)
                            {
                                callbacks_.on_audio_testing_queue_full();
                            }
                        }
                        audio_queue_cv_.notify_all();
                    }
                    else
                    {
                        ESP_LOGE(TAG, "Failed to encode testing audio data");
                    }
                    break;
                }

                default:
                    ESP_LOGE(TAG, "Unknown audio task type: %d", task->type);
                    break;
            }

            continue;
        }

        // Process decoding tasks (Opus -> PCM)
        if (!audio_decode_queue_.empty())
        {
            auto packet = std::move(audio_decode_queue_.front());
            audio_decode_queue_.pop_front();
            audio_queue_cv_.notify_all();
            lock.unlock();

            // Configure decoder if sample rate or frame duration changed
            if (opus_decoder_->sample_rate() != packet->sample_rate || 
                opus_decoder_->duration_ms() != packet->frame_duration)
            {
                SetDecodeSampleRate(packet->sample_rate, packet->frame_duration);
            }

            // Decode Opus packet to PCM
            std::vector<int16_t> decoded_pcm;
            if (opus_decoder_->Decode(packet->payload.data(), packet->payload.size(), decoded_pcm))
            {
                // Resample if needed
                if (opus_decoder_->sample_rate() != codec_->output_sample_rate())
                {
                    auto resampled = std::vector<int16_t>(output_resampler_.GetOutputSamples(decoded_pcm.size()));
                    output_resampler_.Process(decoded_pcm.data(), decoded_pcm.size(), resampled.data());
                    decoded_pcm = std::move(resampled);
                }

                // Create playback task
                auto playback_task = std::make_unique<AudioTask>();
                playback_task->type = kAudioTaskTypeDecodeToPlaybackQueue;
                playback_task->pcm = std::move(decoded_pcm);
                playback_task->timestamp = packet->timestamp;

                // Add to playback queue
                std::unique_lock<std::mutex> play_lock(audio_queue_mutex_);
                audio_queue_cv_.wait(play_lock, [this]()
                                     { return audio_playback_queue_.size() < MAX_PLAYBACK_TASKS_IN_QUEUE; });

                audio_playback_queue_.push_back(std::move(playback_task));
                audio_queue_cv_.notify_all();
            }
            else
            {
                ESP_LOGE(TAG, "Failed to decode audio packet");
            }

            debug_statistics_.decode_count++;
            continue;
        }
    }

    ESP_LOGW(TAG, "Opus codec task stopped");
}

