void AudioService::EnableWakeWordDetection(bool enable)
{
    ESP_LOGD(TAG, "%s wake word detection", enable ? "Enabling" : "Disabling");

    if (enable) {
        // Check if wake word detection is already running
        EventBits_t bits = xEventGroupGetBits(event_group_);
        if (bits & AS_EVENT_WAKE_WORD_RUNNING) {
            ESP_LOGD(TAG, "Wake word detection already enabled");
            return;
        }

        // Initialize wake word detection if we have a wake word instance
        if (wake_word_) {
            // Make sure no audio is playing
            ResetDecoder();
            audio_input_need_warmup_ = true;

            // Initialize wake word if not already done
            if (!wake_word_->IsInitialized()) {
                wake_word_->Initialize(codec_, OPUS_FRAME_DURATION_MS, models_list_);
            }

            // Start the wake word detection
            wake_word_->Start();

            // Set the event flag to enable wake word feeding in AudioInputTask
            xEventGroupSetBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);

            ESP_LOGI(TAG, "Wake word detection enabled");
        } else {
            ESP_LOGW(TAG, "No wake word model available, cannot enable detection");
        }
    } else {
        // Stop wake word detection
        if (wake_word_) {
            wake_word_->Stop();
        }

        // Clear the event flag to stop wake word feeding in AudioInputTask
        xEventGroupClearBits(event_group_, AS_EVENT_WAKE_WORD_RUNNING);

        ESP_LOGI(TAG, "Wake word detection disabled");
    }
}

