void AudioService::PlaySound(const std::string_view &ogg)
{
    if (ogg.empty()) {
        ESP_LOGE(TAG, "Empty OGG data provided");
        return;
    }

    // Enable output if not already enabled
    if (!codec_->output_enabled()) {
        esp_timer_stop(audio_power_timer_);
        esp_timer_start_periodic(audio_power_timer_, AUDIO_POWER_CHECK_INTERVAL_MS * 1000);
        codec_->EnableOutput(true);
    }

    // Simple OGG parser to extract Opus packets
    const uint8_t* data = reinterpret_cast<const uint8_t*>(ogg.data());
    size_t data_size = ogg.size();
    size_t offset = 0;

    int sample_rate = 48000; // Default Opus sample rate
    int channels = 1;        // Default mono
    bool header_parsed = false;

    // Parse OGG pages
    while (offset + 27 < data_size) {
        // Check OGG capture pattern
        if (memcmp(data + offset, "OggS", 4) != 0) {
            ESP_LOGE(TAG, "Invalid OGG signature at offset %zu", offset);
            break;
        }

        // Parse OGG page header
        uint8_t header_type = data[offset + 5];
        uint32_t granule_pos = *reinterpret_cast<const uint32_t*>(data + offset + 6);
        uint32_t bitstream_serial = *reinterpret_cast<const uint32_t*>(data + offset + 14);
        uint32_t page_seq_num = *reinterpret_cast<const uint32_t*>(data + offset + 18);
        uint8_t segments_count = data[offset + 26];

        // Calculate segment table offset
        size_t segment_table_offset = offset + 27;
        if (segment_table_offset + segments_count > data_size) {
            ESP_LOGE(TAG, "Segment table exceeds data size");
            break;
        }

        // Calculate total page data size
        size_t page_data_size = 0;
        for (int i = 0; i < segments_count; i++) {
            page_data_size += data[segment_table_offset + i];
        }

        size_t page_payload_offset = segment_table_offset + segments_count;
        if (page_payload_offset + page_data_size > data_size) {
            ESP_LOGE(TAG, "Page payload exceeds data size");
            break;
        }

        // Process page payloads
        size_t payload_offset = page_payload_offset;
        for (int seg_idx = 0; seg_idx < segments_count; seg_idx++) {
            uint8_t segment_size = data[segment_table_offset + seg_idx];

            if (payload_offset + segment_size > data_size) {
                ESP_LOGE(TAG, "Segment exceeds data size");
                break;
            }

            // Check for Opus header packets
            if (!header_parsed && segment_size >= 8) {
                // Check for OpusHead identifier
                if (memcmp(data + payload_offset, "OpusHead", 8) == 0) {
                    // Parse Opus header
                    if (segment_size >= 19) {
                        uint8_t version = data[payload_offset + 8];
                        channels = data[payload_offset + 9];
                        uint16_t pre_skip = *reinterpret_cast<const uint16_t*>(data + payload_offset + 10);
                        sample_rate = *reinterpret_cast<const uint32_t*>(data + payload_offset + 12);
                        uint16_t output_gain = *reinterpret_cast<const uint16_t*>(data + payload_offset + 16);

                        ESP_LOGI(TAG, "Opus Header: version=%d, channels=%d, sample_rate=%d", 
                                version, channels, sample_rate);

                        // Configure decoder with parsed parameters
                        SetDecodeSampleRate(sample_rate, OPUS_FRAME_DURATION_MS);
                        header_parsed = true;
                    }
                }
                // Skip other header types (OpusTags, etc.)
                else if (memcmp(data + payload_offset, "OpusTags", 8) == 0) {
                    // Comment header - skip for now
                    ESP_LOGD(TAG, "Skipping OpusTags header");
                }
                // Assume audio data if not a known header
                else {
                    // This is likely audio data, process it
                    std::vector<uint8_t> opus_packet(data + payload_offset, data + payload_offset + segment_size);

                    // Decode the Opus packet
                    auto task = std::make_unique<AudioTask>();
                    task->type = kAudioTaskTypeDecodeToPlaybackQueue;
                    task->timestamp = 0;

                    if (opus_decoder_->Decode(std::move(opus_packet), task->pcm)) {
                        // Resample if needed
                        if (opus_decoder_->sample_rate() != codec_->output_sample_rate()) {
                            int target_size = output_resampler_.GetOutputSamples(task->pcm.size());
                            std::vector<int16_t> resampled(target_size);
                            output_resampler_.Process(task->pcm.data(), task->pcm.size(), resampled.data());
                            task->pcm = std::move(resampled);
                        }

                        // Add to playback queue
                        {
                            std::lock_guard<std::mutex> lock(audio_queue_mutex_);
                            audio_playback_queue_.push_back(std::move(task));
                        }
                        audio_queue_cv_.notify_all();
                    } else {
                        ESP_LOGE(TAG, "Failed to decode Opus packet");
                    }
                }
            } else if (header_parsed) {
                // Process audio data packets
                std::vector<uint8_t> opus_packet(data + payload_offset, data + payload_offset + segment_size);

                // Decode the Opus packet
                auto task = std::make_unique<AudioTask>();
                task->type = kAudioTaskTypeDecodeToPlaybackQueue;
                task->timestamp = 0;

                if (opus_decoder_->Decode(std::move(opus_packet), task->pcm)) {
                    // Resample if needed
                    if (opus_decoder_->sample_rate() != codec_->output_sample_rate()) {
                        int target_size = output_resampler_.GetOutputSamples(task->pcm.size());
                        std::vector<int16_t> resampled(target_size);
                        output_resampler_.Process(task->pcm.data(), task->pcm.size(), resampled.data());
                        task->pcm = std::move(resampled);
                    }

                    // Add to playback queue
                    {
                        std::lock_guard<std::mutex> lock(audio_queue_mutex_);
                        audio_playback_queue_.push_back(std::move(task));
                    }
                    audio_queue_cv_.notify_all();
                } else {
                    ESP_LOGE(TAG, "Failed to decode Opus packet");
                }
            }

            payload_offset += segment_size;
        }

        // Move to next page
        offset = page_payload_offset + page_data_size;
    }

    ESP_LOGI(TAG, "Finished parsing OGG file");
}

