AudioDebugger::AudioDebugger() {
#if CONFIG_USE_AUDIO_DEBUGGER
    udp_sockfd_ = -1;

    // Parse the server address and port from configuration
    std::string server_config = CONFIG_AUDIO_DEBUG_UDP_SERVER;
    size_t colon_pos = server_config.find(':');

    if (colon_pos == std::string::npos) {
        ESP_LOGE(TAG, "Invalid server configuration format, expected IP:PORT");
        return;
    }

    std::string ip_str = server_config.substr(0, colon_pos);
    std::string port_str = server_config.substr(colon_pos + 1);

    int port = atoi(port_str.c_str());
    if (port <= 0 || port > 65535) {
        ESP_LOGE(TAG, "Invalid port number: %s", port_str.c_str());
        return;
    }

    // Create UDP socket
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
        return;
    }

    // Configure server address structure
    memset(&udp_server_addr_, 0, sizeof(udp_server_addr_));
    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(port);

    if (inet_aton(ip_str.c_str(), &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid IP address: %s", ip_str.c_str());
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
    }

    ESP_LOGI(TAG, "UDP debugger initialized to %s:%d", ip_str.c_str(), port);
#else
    udp_sockfd_ = -1;
#endif
}

