void AfeWakeWord::AudioDetectionTask()
{
    const TickType_t xMaxBlockTime = pdMS_TO_TICKS(100);
    int wake_word_id = -1;

    while (true) {
        // Wait for detection to be enabled
        EventBits_t uxBits = xEventGroupWaitBits(event_group_, 
                                                DETECTION_RUNNING_EVENT, 
                                                pdFALSE, 
                                                pdTRUE, 
                                                xMaxBlockTime);

        if ((uxBits & DETECTION_RUNNING_EVENT) != 0) {
            if (afe_data_ != nullptr && afe_iface_ != nullptr) {
                // Fetch audio data from AFE
                int fetch_flag = 0;
                auto audio_chunk = afe_iface_->fetch(afe_data_, &fetch_flag);

                if (audio_chunk != nullptr) {
                    // Store the audio data for potential wake word capture
                    StoreWakeWordData(static_cast<const int16_t*>(audio_chunk), 
                                    afe_iface_->get_fetch_chunksize(afe_data_));

                    // Check for wake word detection
                    wake_word_id = afe_iface_->detect(afe_data_);

                    if (wake_word_id > 0) {
                        // Wake word detected
                        ESP_LOGI(TAG, "Wake word detected with ID: %d", wake_word_id);

                        // Stop detection temporarily
                        Stop();

                        // Get the wake word string
                        if (wake_word_id <= static_cast<int>(wake_words_.size())) {
                            last_detected_wake_word_ = wake_words_[wake_word_id - 1];

                            // Trigger the callback if set
                            if (wake_word_detected_callback_) {
                                wake_word_detected_callback_(last_detected_wake_word_);
                            }

                            // Start encoding the captured wake word data
                            EncodeWakeWordData();
                        }

                        // Restart detection
                        Start();
                    }
                }
            }
        }
    }
}

