void AfeWakeWord::EncodeWakeWordData()
{
    // Allocate task stack in SPIRAM for better memory utilization
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(4096, MALLOC_CAP_SPIRAM);
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate encode task stack");
            return;
        }
    }

    // Allocate task buffer in internal memory for reliability
    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate encode task buffer");
            return;
        }
    }

    // Create the encoding task if it doesn't exist
    if (wake_word_encode_task_ == nullptr) {
        wake_word_encode_task_ = xTaskCreateStatic(
            [](void *arg) {
                auto this_ = (AfeWakeWord*)arg;
                this_->EncodeWakeWordDataTask();
                // Task cleanup
                this_->wake_word_encode_task_ = nullptr;
                vTaskDelete(NULL);
            },
            "wake_word_encode",
            4096,
            this,
            5, // Higher priority for real-time encoding
            wake_word_encode_task_stack_,
            wake_word_encode_task_buffer_
        );
    }
}

void AfeWakeWord::EncodeWakeWordDataTask()
{
    // Initialize Opus encoder with low complexity settings
    OpusEncoder *encoder = nullptr;
    int opus_error = 0;

    // Create Opus encoder with low complexity for fast encoding
    encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, &opus_error);
    if (opus_error != OPUS_OK || encoder == nullptr) {
        ESP_LOGE(TAG, "Failed to create Opus encoder: %d", opus_error);
        return;
    }

    // Configure encoder for low complexity and real-time performance
    opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));          // Lowest complexity
    opus_encoder_ctl(encoder, OPUS_SET_BITRATE(16000));         // 16kbps bitrate
    opus_encoder_ctl(encoder, OPUS_SET_VBR(0));                 // CBR for predictable timing
    opus_encoder_ctl(encoder, OPUS_SET_DTX(0));                 // Disable DTX for consistent processing

    const size_t pcm_frame_size = 512;  // 32ms at 16kHz
    const size_t max_opus_size = 128;   // Maximum expected Opus packet size

    std::vector<uint8_t> opus_buffer(max_opus_size);

    while (true) {
        // Check if we have PCM data to process
        std::unique_lock<std::mutex> lock(wake_word_mutex_);

        // Wait for PCM data to be available
        if (wake_word_pcm_.empty()) {
            lock.unlock();
            vTaskDelay(pdMS_TO_TICKS(10)); // Small delay to prevent busy waiting
            continue;
        }

        // Get the next PCM chunk to encode
        std::vector<int16_t> pcm_data = std::move(wake_word_pcm_.front());
        wake_word_pcm_.pop_front();
        lock.unlock();

        // Process PCM data in chunks
        size_t samples_processed = 0;
        while (samples_processed < pcm_data.size()) {
            size_t remaining_samples = pcm_data.size() - samples_processed;
            size_t chunk_size = (remaining_samples > pcm_frame_size) ? pcm_frame_size : remaining_samples;

            // Encode the PCM chunk to Opus
            int encoded_bytes = opus_encode(
                encoder,
                &pcm_data[samples_processed],
                chunk_size,
                opus_buffer.data(),
                max_opus_size
            );

            if (encoded_bytes > 0) {
                // Store the encoded Opus packet
                std::lock_guard<std::mutex> guard(wake_word_mutex_);
                wake_word_opus_.emplace_back(std::vector<uint8_t>(opus_buffer.begin(), 
                                                                 opus_buffer.begin() + encoded_bytes));
                wake_word_cv_.notify_one(); // Signal that new Opus data is available
            } else {
                ESP_LOGW(TAG, "Opus encoding failed with error: %d", encoded_bytes);
            }

            samples_processed += chunk_size;
        }

        // Small yield to allow other tasks to run
        vTaskDelay(1);
    }

    // Cleanup encoder
    if (encoder) {
        opus_encoder_destroy(encoder);
    }
}

