void CustomWakeWord::ParseWakenetModelConfig()
{
    // Read the index.json file from the models directory
    std::string config_path = std::string(models_->model_path) + "/index.json";
    std::string json_content;

    // Try to read the file content
    if (!Assets::ReadFile(config_path, json_content)) {
        ESP_LOGE(TAG, "Failed to read config file: %s", config_path.c_str());
        return;
    }

    // Parse JSON content
    cJSON *root = cJSON_Parse(json_content.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON config file: %s", config_path.c_str());
        return;
    }

    // Parse language
    cJSON *language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = language_item->valuestring;
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Parse duration
    cJSON *duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    }

    // Parse threshold
    cJSON *threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
        ESP_LOGI(TAG, "Parsed threshold: %f", threshold_);
    }

    // Parse commands array
    cJSON *commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array != nullptr && cJSON_IsArray(commands_array)) {
        int commands_count = cJSON_GetArraySize(commands_array);
        ESP_LOGI(TAG, "Parsing %d commands", commands_count);

        for (int i = 0; i < commands_count; i++) {
            cJSON *command_obj = cJSON_GetArrayItem(commands_array, i);
            if (command_obj == nullptr) continue;

            cJSON *command_item = cJSON_GetObjectItem(command_obj, "command");
            cJSON *text_item = cJSON_GetObjectItem(command_obj, "text");
            cJSON *action_item = cJSON_GetObjectItem(command_obj, "action");

            if (command_item != nullptr && text_item != nullptr && 
                cJSON_IsString(command_item) && cJSON_IsString(text_item)) {

                Command cmd;
                cmd.command = command_item->valuestring;
                cmd.text = text_item->valuestring;
                cmd.action = (action_item != nullptr && cJSON_IsString(action_item)) ? 
                            action_item->valuestring : "wake";

                commands_.push_back(cmd);

                ESP_LOGI(TAG, "Parsed command: %s, text: %s, action: %s", 
                         cmd.command.c_str(), cmd.text.c_str(), cmd.action.c_str());
            }
        }
    }

    // Clean up JSON parser
    cJSON_Delete(root);
}

