bool CustomWakeWord::Initialize(AudioCodec *codec, srmodel_list_t *models_list)
{
    codec_ = codec;

    // Initialize speech recognition models
    if (models_list == nullptr) {
        models_ = esp_srmodel_init("model");
    } else {
        models_ = models_list;
    }

    if (models_ == nullptr || models_->num == -1) {
        ESP_LOGE(TAG, "Failed to initialize speech recognition models");
        return false;
    }

    // Parse model configuration from index.json
    ParseWakenetModelConfig();

    // Find and initialize multinet model
    mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str(), NULL, ESP_MN_SUFFIX_NETWORK);
    if (mn_name_ == nullptr) {
        ESP_LOGE(TAG, "Failed to find multinet model for language: %s", language_.c_str());
        return false;
    }

    ESP_LOGI(TAG, "Using multinet model: %s", mn_name_);

    // Get multinet interface
    multinet_ = esp_mn_handle_from_name(mn_name_);
    if (multinet_ == nullptr) {
        ESP_LOGE(TAG, "Failed to get multinet interface for model: %s", mn_name_);
        return false;
    }

    // Create multinet model data
    multinet_model_data_ = multinet_->create(mn_name_, 5000, 0, 0);
    if (multinet_model_data_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Set detection threshold
    multinet_->set_det_threshold(multinet_model_data_, threshold_, 0);

    // Register custom commands
    for (size_t i = 0; i < commands_.size(); i++) {
        const auto &command = commands_[i];
        esp_mn_commands_add(multinet_model_data_, static_cast<int>(i + 1), command.text.c_str());
        ESP_LOGI(TAG, "Registered command %d: %s", static_cast<int>(i + 1), command.text.c_str());
    }

    ESP_LOGI(TAG, "Custom wake word detection initialized successfully");
    return true;
}

