    // For stereo, we extract the left channel only
    bool is_stereo = (data.size() % 2 == 0);

    size_t feed_size = GetFeedSize();
    if (feed_size == 0) {
        return;
    }

    // Process the incoming data in chunks
    static std::vector<int16_t> audio_buffer;

    if (is_stereo) {
        // Extract left channel from stereo data
        for (size_t i = 0; i < data.size(); i += 2) {
            audio_buffer.push_back(data[i]);

