void CustomWakeWord::EncodeWakeWordData()
{
    // Allocate stack for the encoding task
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = static_cast<uint8_t*>(heap_caps_malloc(4096, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate stack for wake word encoding task");
            return;
        }
    }

    // Create a new task to handle the encoding process
    xTaskCreatePinnedToCore([](void* arg) {
        CustomWakeWord* instance = static_cast<CustomWakeWord*>(arg);

        // Initialize Opus encoder with low complexity settings
        OpusEncoder* encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, nullptr);
        if (encoder == nullptr) {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            vTaskDelete(nullptr);
            return;
        }

        // Set low complexity encoding
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(1));
        opus_encoder_ctl(encoder, OPUS_SET_BITRATE(16000));
        opus_encoder_ctl(encoder, OPUS_SET_SIGNAL(OPUS_SIGNAL_VOICE));

        // Calculate maximum encoded frame size (should be less than 1275 bytes for 20ms frame)
        const int max_frame_size = 4000; // Conservative estimate
        std::vector<uint8_t> encoded_buffer(max_frame_size);

        // Lock mutex to access PCM data
        std::lock_guard<std::mutex> lock(instance->wake_word_mutex_);

        // Process each PCM segment
        for (const auto& pcm_segment : instance->wake_word_pcm_) {
            // Encode PCM data to Opus
            int encoded_bytes = opus_encode(encoder, 
                                          pcm_segment.data(), 
                                          pcm_segment.size(), 
                                          encoded_buffer.data(), 
                                          max_frame_size);

            if (encoded_bytes > 0) {
                // Store encoded data
                std::vector<uint8_t> opus_frame(encoded_buffer.begin(), encoded_buffer.begin() + encoded_bytes);
                instance->wake_word_opus_.push_back(std::move(opus_frame));
            } else {
                ESP_LOGW(TAG, "Opus encoding failed with error code: %d", encoded_bytes);
            }
        }

        // Append termination marker (empty Opus frame indicates end of stream)
        std::vector<uint8_t> termination_marker;
        instance->wake_word_opus_.push_back(std::move(termination_marker));

        // Clean up Opus encoder
        opus_encoder_destroy(encoder);

        // Notify waiting threads that Opus data is available
        instance->wake_word_cv_.notify_all();

        // Delete the task
        vTaskDelete(nullptr);

    }, "wake_word_encode", 4096, this, 5, nullptr, PRO_CPU_NUM);
}

