std::string Board::GetSystemInfoJson() {
    cJSON *root = cJSON_CreateObject();

    // Hardware details
    cJSON_AddStringToObject(root, "chip_model", SystemInfo::GetChipModelName().c_str());
    cJSON_AddNumberToObject(root, "flash_size", SystemInfo::GetFlashSize());
    cJSON_AddStringToObject(root, "mac_address", SystemInfo::GetMacAddress().c_str());

    // Application metadata
    auto app_desc = esp_app_get_description();
    cJSON_AddStringToObject(root, "app_name", app_desc->project_name);
    cJSON_AddStringToObject(root, "app_version", app_desc->version);
    cJSON_AddStringToObject(root, "compile_time", app_desc->time);

    // Partition table data
    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition) {
        cJSON_AddStringToObject(root, "partition_label", running_partition->label);
        cJSON_AddNumberToObject(root, "partition_address", running_partition->address);
        cJSON_AddNumberToObject(root, "partition_size", running_partition->size);
    }

    // Runtime information
    cJSON_AddNumberToObject(root, "min_free_heap_size", SystemInfo::GetMinimumFreeHeapSize());

    // Unique identifier
    cJSON_AddStringToObject(root, "uuid", uuid_.c_str());

    // Board name
    cJSON_AddStringToObject(root, "board_name", BOARD_NAME);

    char *json_string = cJSON_PrintUnformatted(root);
    std::string result(json_string ? json_string : "{}");

    if (json_string) {
        free(json_string);
    }
    cJSON_Delete(root);

    return result;
}

