void WifiBoard::OnNetworkEvent(NetworkEvent event, const std::string &data)
{
    switch (event) {
        case NetworkEvent::Scanning:
            ESP_LOGI(TAG, "WiFi scanning started");
            break;

        case NetworkEvent::Connecting:
            ESP_LOGI(TAG, "Connecting to WiFi network: %s", data.c_str());
            break;

        case NetworkEvent::Connected:
            ESP_LOGI(TAG, "WiFi connected to: %s", data.c_str());
            // Stop connection timeout timer
            if (connect_timer_) {
                esp_timer_stop(connect_timer_);
            }
            // Release provisioning resources
            in_config_mode_ = false;
            // Notify application of network connection
            Application::GetInstance().HandleNetworkConnectedEvent();
            break;

        case NetworkEvent::Disconnected:
            ESP_LOGW(TAG, "WiFi disconnected");
            // Attempt reconnection if not in config mode
            if (!in_config_mode_) {
                TryWifiConnect();
            }
            break;

        case NetworkEvent::WifiConfigModeEnter:
            ESP_LOGI(TAG, "Entering WiFi configuration mode");
            in_config_mode_ = true;
            Application::GetInstance().SetDeviceState(kDeviceStateWifiConfiguring);
            break;

        case NetworkEvent::WifiConfigModeExit:
            ESP_LOGI(TAG, "Exiting WiFi configuration mode");
            in_config_mode_ = false;
            // Stop any existing connection attempt
            if (connect_timer_) {
                esp_timer_stop(connect_timer_);
            }
            // Try to connect with newly configured credentials
            TryWifiConnect();
            break;

        default:
            ESP_LOGW(TAG, "Unhandled network event: %d", static_cast<int>(event));
            break;
    }

    // Notify external callback if set
    if (network_event_callback_) {
        network_event_callback_(event, data);
    }
}

