void WifiBoard::EnterWifiConfigMode()
{
    // Get current application instance
    auto& app = Application::GetInstance();
    auto current_state = app.GetDeviceState();

    // Validate current device state to prevent conflicts
    // Don't enter config mode if already in certain states
    if (current_state == kDeviceStateWifiConfiguring) {
        ESP_LOGW(TAG, "Already in WiFi config mode");
        return;
    }

    ESP_LOGI(TAG, "Entering WiFi config mode from state: %d", static_cast<int>(current_state));

    // Gracefully shut down active audio/communication processes
    // Stop any ongoing audio operations
    if (current_state == kDeviceStateListening || 
        current_state == kDeviceStateSpeaking || 
        current_state == kDeviceStateConnecting) {
        ESP_LOGI(TAG, "Stopping active audio/communication processes");

        // Close audio channel if protocol exists
        auto protocol = app.GetProtocol();
        if (protocol) {
            protocol->CloseAudioChannel();
        }
    }

    // Stop any ongoing network operations
    WifiManager::GetInstance().StopStation();

    // Display notification about entering config mode
    Display* display = Board::GetInstance().GetDisplay();
    if (display) {
        display->ShowMessage(Lang::Strings::WIFI_CONFIG_MODE, "gear");
    }

    // Set device state to indicate we're configuring WiFi
    app.SetDeviceState(kDeviceStateWifiConfiguring);

    // Start the actual WiFi configuration mode
    StartWifiConfigMode();
}

