std::string WifiBoard::GetDeviceStatusJson()
{
    std::string json = R"({)";

    // Audio speaker volume
    auto &app = Application::GetInstance();
    int volume = app.GetSpeakerVolume();
    json += R"("audio":{"volume":)" + std::to_string(volume) + R"(},)";

    // Screen brightness and theme
    auto display = GetDisplay();
    if (display) {
        int brightness = display->GetBrightness();
        std::string theme = display->GetTheme();
        json += R"("display":{"brightness":)" + std::to_string(brightness) + R"(,"theme":")" + theme + R"("},)";
    }

    // Battery level and charging state
    int battery_level = SystemInfo::GetBatteryLevel();
    bool is_charging = SystemInfo::IsCharging();
    json += R"("power":{"battery":)" + std::to_string(battery_level) + R"(,"charging":)" + (is_charging ? "true" : "false") + R"(},)";

    // WiFi network details
    auto &wifi = WifiManager::GetInstance();
    if (!wifi.IsConfigMode() && wifi.IsConnected()) {
        std::string ssid = wifi.GetSsid();
        int rssi = wifi.GetRssi();
        json += R"("wifi":{"ssid":")" + ssid + R"(","rssi":)" + std::to_string(rssi) + R"(},)";
    } else if (wifi.IsConfigMode()) {
        json += R"("wifi":{"config_mode":true},)";
    } else {
        json += R"("wifi":{"connected":false},)";
    }

    // Chip temperature
    float temperature = SystemInfo::GetChipTemperature();
    json += R"("system":{"temperature":)" + std::to_string(temperature) + R"(})";

    json += R"(})";
    return json;
}

