void LcdDisplay::SetPreviewImage(std::unique_ptr<LvglImage> image)
{
    DisplayLockGuard lock(this);

    // Stop any existing preview timer
    esp_timer_stop(preview_timer_);

    // If image is null, clean up and show emoji instead
    if (image == nullptr) {
        if (preview_image_ != nullptr) {
            lv_obj_add_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);
        }
        if (emoji_box_ != nullptr) {
            lv_obj_remove_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
        }
        preview_image_cached_.reset();

        // Restart GIF animation if it exists
        if (gif_controller_) {
            gif_controller_->Start();
        }
        return;
    }

    // Cache the image
    preview_image_cached_ = std::move(image);
    auto img_dsc = preview_image_cached_->image_dsc();

    // Validate image dimensions
    if (img_dsc->header.w <= 0 || img_dsc->header.h <= 0) {
        ESP_LOGW(TAG, "Invalid image dimensions: %d x %d, using default size", 
                 img_dsc->header.w, img_dsc->header.h);
    }

    // Define maximum preview dimensions (80% of screen size)
    const int max_width = width_ * 0.8;
    const int max_height = height_ * 0.8;

    // Calculate scaled dimensions while maintaining aspect ratio
    int display_width = img_dsc->header.w;
    int display_height = img_dsc->header.h;

    if (display_width > 0 && display_height > 0) {
        // Scale to fit within bounds while preserving aspect ratio
        float scale_x = (float)max_width / display_width;
        float scale_y = (float)max_height / display_height;
        float scale = std::min(scale_x, scale_y);

        // Ensure we don't upscale small images beyond reason
        scale = std::min(scale, 1.0f);

        if (scale < 1.0f) {
            display_width = (int)(display_width * scale);
            display_height = (int)(display_height * scale);
        }
    } else {
        // Use default size if dimensions are invalid
        display_width = max_width / 2;
        display_height = max_height / 2;
        ESP_LOGW(TAG, "Using default preview size: %d x %d", display_width, display_height);
    }

    // Create or reuse preview image object
    if (preview_image_ == nullptr) {
        preview_image_ = lv_image_create(content_);
        if (preview_image_ == nullptr) {
            ESP_LOGE(TAG, "Failed to create preview image object");
            preview_image_cached_.reset();
            return;
        }
    }

    // Configure the image
    lv_image_set_src(preview_image_, img_dsc);
    lv_obj_set_size(preview_image_, display_width, display_height);
    lv_obj_center(preview_image_);

    // Create a styled message bubble container for the image
    lv_obj_t* image_bubble = lv_obj_create(content_);
    if (image_bubble == nullptr) {
        ESP_LOGE(TAG, "Failed to create image bubble container");
        return;
    }

    // Style the bubble
    auto lvgl_theme = static_cast<LvglTheme*>(current_theme_);
    lv_obj_set_style_radius(image_bubble, 8, 0);
    lv_obj_set_style_bg_color(image_bubble, lvgl_theme->system_bubble_color(), 0);
    lv_obj_set_style_bg_opa(image_bubble, LV_OPA_70, 0);
    lv_obj_set_style_border_width(image_bubble, 0, 0);
    lv_obj_set_style_pad_all(image_bubble, lvgl_theme->spacing(4), 0);

    // Set bubble size to accommodate the image
    lv_obj_set_size(image_bubble, display_width + lvgl_theme->spacing(8), 
                    display_height + lvgl_theme->spacing(8));
    lv_obj_center(image_bubble);

    // Move the image into the bubble
    lv_obj_set_parent(preview_image_, image_bubble);
    lv_obj_center(preview_image_);

    // Mark this as an image bubble for theme updates
    lv_obj_set_user_data(image_bubble, (void*)"image");

    // Hide emoji box and stop GIF
    if (emoji_box_ != nullptr) {
        lv_obj_add_flag(emoji_box_, LV_OBJ_FLAG_HIDDEN);
    }
    if (gif_controller_) {
        gif_controller_->Stop();
    }

    // Make sure preview image is visible
    lv_obj_remove_flag(preview_image_, LV_OBJ_FLAG_HIDDEN);

    // Start timer to automatically hide the preview
    ESP_ERROR_CHECK(esp_timer_start_once(preview_timer_, PREVIEW_IMAGE_DURATION_MS * 1000));
}

