{
    DisplayLockGuard lock(this);

    // Validate inputs and content area
    if (content_ == nullptr || role == nullptr || content == nullptr) {
        return;
    }

    // Skip empty messages
    if (strlen(content) == 0) {
        return;
    }

    auto lvgl_theme = static_cast<LvglTheme *>(current_theme_);
    auto text_font = lvgl_theme->text_font()->font();

    // Remove old messages if we've reached the limit
    uint32_t child_count = lv_obj_get_child_cnt(content_);
    while (child_count >= MAX_MESSAGES) {
        lv_obj_t *oldest_msg = lv_obj_get_child(content_, 0);
        if (oldest_msg != nullptr) {
            lv_obj_del(oldest_msg);
        }
        child_count--;
    }

    bool is_system_message = (strcmp(role, "system") == 0);
    bool is_user_message = (strcmp(role, "user") == 0);
    bool is_assistant_message = (strcmp(role, "assistant") == 0) || (strcmp(role, "AI") == 0);

    lv_obj_t *message_container = nullptr;
    lv_obj_t *message_bubble = nullptr;
    lv_obj_t *message_text = nullptr;

    if (is_system_message) {
        // System messages: full-width, centered text without bubble
        message_container = lv_obj_create(content_);
        lv_obj_set_width(message_container, LV_PCT(100));
        lv_obj_set_style_pad_hor(message_container, 0, 0);
        lv_obj_set_style_pad_ver(message_container, lvgl_theme->spacing(2), 0);
        lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(message_container, 0, 0);

        message_text = lv_label_create(message_container);
        lv_label_set_text(message_text, content);
        lv_obj_set_style_text_align(message_text, LV_TEXT_ALIGN_CENTER, 0);
        lv_obj_set_style_text_color(message_text, lvgl_theme->system_text_color(), 0);
        lv_obj_set_width(message_text, LV_PCT(100));
        lv_label_set_long_mode(message_text, LV_LABEL_LONG_WRAP);

        // Mark as system message
        lv_obj_set_user_data(message_container, (void *)"system");
    } else {
        // Regular messages (user/assistant): create bubble containers
        message_container = lv_obj_create(content_);
        lv_obj_set_width(message_container, LV_PCT(100));
        lv_obj_set_style_pad_hor(message_container, 0, 0);
        lv_obj_set_style_pad_ver(message_container, 0, 0);
        lv_obj_set_style_bg_opa(message_container, LV_OPA_TRANSP, 0);
        lv_obj_set_style_border_width(message_container, 0, 0);
        lv_obj_set_style_flex_grow(message_container, 0, 0);

        message_bubble = lv_obj_create(message_container);
        lv_obj_set_style_radius(message_bubble, 8, 0);
        lv_obj_set_style_pad_all(message_bubble, lvgl_theme->spacing(3), 0);
        lv_obj_set_style_border_width(message_bubble, 1, 0);
        lv_obj_set_style_border_color(message_bubble, lvgl_theme->border_color(), 0);
        lv_obj_set_style_max_width(message_bubble, LV_PCT(80), 0);
        lv_obj_set_style_flex_grow(message_bubble, 0, 0);

        message_text = lv_label_create(message_bubble);
        lv_label_set_text(message_text, content);
        lv_obj_set_style_text_color(message_text, lvgl_theme->text_color(), 0);
        lv_label_set_long_mode(message_text, LV_LABEL_LONG_WRAP);
        lv_obj_set_width(message_text, LV_SIZE_CONTENT);

        if (is_user_message) {
            // User messages: right-aligned green bubble
            lv_obj_set_style_bg_color(message_bubble, lvgl_theme->user_bubble_color(), 0);
            lv_obj_align(message_bubble, LV_ALIGN_RIGHT_MID, 0, 0);
            lv_obj_set_user_data(message_bubble, (void *)"user");
        } else if (is_assistant_message) {
            // Assistant messages: left-aligned gray bubble
            lv_obj_set_style_bg_color(message_bubble, lvgl_theme->assistant_bubble_color(), 0);
            lv_obj_align(message_bubble, LV_ALIGN_LEFT_MID, 0, 0);
            lv_obj_set_user_data(message_bubble, (void *)"assistant");

            // Hide AI logo for non-system messages
            if (emoji_label_ != nullptr) {
                lv_obj_add_flag(emoji_label_, LV_OBJ_FLAG_HIDDEN);
            }
            if (emoji_image_ != nullptr) {
                lv_obj_add_flag(emoji_image_, LV_OBJ_FLAG_HIDDEN);
            }
        }
    }

    // Scroll to show the new message
    lv_obj_scroll_to_view_recursive(message_container, LV_ANIM_ON);
}

