bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Stop any existing reconnect timer
    if (reconnect_timer_ != nullptr) {
        esp_timer_stop(reconnect_timer_);
    }

    // Get MQTT configuration from settings
    auto& settings = Settings::GetInstance();
    std::string broker_url = settings.GetMqttBrokerUrl();
    std::string username = settings.GetMqttUsername();
    std::string password = settings.GetMqttPassword();
    std::string client_id = settings.GetMqttClientId();
    int port = settings.GetMqttPort();

    // Validate configuration
    if (broker_url.empty() || client_id.empty()) {
        ESP_LOGE(TAG, "MQTT configuration is incomplete");
        if (report_error) {
            SetError(Lang::Strings::CONFIGURATION_ERROR);
        }
        return false;
    }

    // Reset previous state
    publish_topic_.clear();
    session_id_.clear();
    error_occurred_ = false;

    // Create MQTT client instance
    auto network = Board::GetInstance().GetNetwork();
    mqtt_ = network->CreateMqtt();

    if (mqtt_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create MQTT client");
        if (report_error) {
            SetError(Lang::Strings::INITIALIZATION_ERROR);
        }
        return false;
    }

    // Configure MQTT client
    mqtt_->SetClientId(client_id);
    if (!username.empty()) {
        mqtt_->SetUsername(username);
    }
    if (!password.empty()) {
        mqtt_->SetPassword(password);
    }

    // Set up connection handler
    mqtt_->OnConnected([this]() {
        ESP_LOGI(TAG, "MQTT connected successfully");

        // Subscribe to response topic
        std::string response_topic = "device/" + Settings::GetInstance().GetMqttClientId() + "/response";
        if (!mqtt_->Subscribe(response_topic, 0)) {
            ESP_LOGE(TAG, "Failed to subscribe to response topic: %s", response_topic.c_str());
            SetError(Lang::Strings::SUBSCRIPTION_ERROR);
            return;
        }

        publish_topic_ = "device/" + Settings::GetInstance().GetMqttClientId() + "/request";

        // Notify application of successful connection
        if (on_connected_ != nullptr) {
            on_connected_();
        }
    });

    // Set up disconnection handler
    mqtt_->OnDisconnected([this](int reason) {
        ESP_LOGW(TAG, "MQTT disconnected with reason: %d", reason);
        error_occurred_ = true;

        // Clear UDP channel if exists
        {
            std::lock_guard<std::mutex> lock(channel_mutex_);
            udp_.reset();
        }

        // Notify about network error
        if (on_network_error_ != nullptr) {
            on_network_error_(Lang::Strings::CONNECTION_LOST);
        }

        // Schedule reconnect attempt if still alive
        if (*alive_) {
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        }
    });

    // Set up message handler
    mqtt_->OnMessage([this](const std::string& topic, const std::string& payload) {
        ESP_LOGD(TAG, "Received MQTT message on topic: %s", topic.c_str());

        // Parse JSON payload
        cJSON *root = cJSON_Parse(payload.c_str());
        if (root == nullptr) {
            ESP_LOGE(TAG, "Failed to parse JSON payload: %s", payload.c_str());
            return;
        }

        // Process different message types
        auto type_item = cJSON_GetObjectItem(root, "type");
        if (type_item != nullptr && cJSON_IsString(type_item)) {
            std::string type(type_item->valuestring);

            if (type == "hello") {
                ParseServerHello(root);
            } else if (on_incoming_json_ != nullptr) {
                on_incoming_json_(root);
            }
        } else {
            ESP_LOGW(TAG, "Received message without valid type field");
        }

        cJSON_Delete(root);
    });

    // Attempt connection
    ESP_LOGI(TAG, "Connecting to MQTT broker: %s:%d", broker_url.c_str(), port);
    if (!mqtt_->Connect(broker_url, port)) {
        ESP_LOGE(TAG, "Failed to connect to MQTT broker");
        if (report_error) {
            SetError(Lang::Strings::CONNECTION_FAILED);
        }

        // Schedule reconnect if alive
        if (*alive_) {
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        }

        return false;
    }

    return true;
}

