bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (packet == nullptr) {
        return false;
    }

    std::lock_guard<std::mutex> lock(channel_mutex_);

    if (udp_ == nullptr || !udp_->IsConnected()) {
        ESP_LOGE(TAG, "UDP channel is not available");
        return false;
    }

    // Update sequence number
    local_sequence_++;

    // Create packet header (16 bytes)
    std::vector<uint8_t> packet_data(16);

    // Type = 0x01 (audio packet)
    packet_data[0] = 0x01;

    // Flags = 0x00
    packet_data[1] = 0x00;

    // Payload length (network byte order)
    uint16_t payload_len = htons(packet->payload.size());
    memcpy(&packet_data[2], &payload_len, sizeof(payload_len));

    // SSRC (should be some identifier, using fixed value or session ID hash)
    uint32_t ssrc = htonl(0x12345678); // TODO: Use proper SSRC
    memcpy(&packet_data[4], &ssrc, sizeof(ssrc));

    // Timestamp (network byte order)
    uint32_t timestamp = htonl(packet->timestamp);
    memcpy(&packet_data[8], &timestamp, sizeof(timestamp));

    // Sequence number (network byte order)
    uint32_t sequence = htonl(local_sequence_);
    memcpy(&packet_data[12], &sequence, sizeof(sequence));

    // Prepare nonce for AES-CTR
    // Based on existing code, aes_nonce_ is used as base, we need to update it
    std::vector<uint8_t> nonce(aes_nonce_.begin(), aes_nonce_.end());

    // Update nonce with packet-specific data (using last 12 bytes typically)
    if (nonce.size() >= 12) {
        // Copy packet size, timestamp, and sequence to nonce
        uint32_t net_payload_len = htonl(packet->payload.size());
        uint32_t net_timestamp = htonl(packet->timestamp);
        uint32_t net_sequence = htonl(local_sequence_);

        // Place these values in the nonce (assuming last 12 bytes are used for counter)
        memcpy(&nonce[nonce.size() - 12], &net_payload_len, 4);
        memcpy(&nonce[nonce.size() - 8], &net_timestamp, 4);
        memcpy(&nonce[nonce.size() - 4], &net_sequence, 4);
    }

    // Encrypt payload using AES-CTR
    std::vector<uint8_t> encrypted_payload(packet->payload.size());
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, packet->payload.size(), &nc_off, 
                                   nonce.data(), stream_block,
                                   (const uint8_t*)packet->payload.data(), 
                                   encrypted_payload.data());

    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Append encrypted payload to packet
    packet_data.insert(packet_data.end(), encrypted_payload.begin(), encrypted_payload.end());

    // Send packet over UDP
    bool success = udp_->Send(reinterpret_cast<const char*>(packet_data.data()), packet_data.size());

    if (!success) {
        ESP_LOGE(TAG, "Failed to send audio packet over UDP");
        return false;
    }

    return true;
}

